import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void typicalMixedEvents() {
        // LOGIN:1, TRANSFER:2, LOGOUT:1 — DECLINED absent from map
        Map<String, Integer> result = new Solution().eventCounts(
                new String[]{"LOGIN", "TRANSFER", "TRANSFER", "LOGOUT"});
        assertEquals(Set.of("LOGIN", "TRANSFER", "LOGOUT"), result.keySet());
        assertEquals(1, result.get("LOGIN"));
        assertEquals(2, result.get("TRANSFER"));
        assertEquals(1, result.get("LOGOUT"));
    }

    @Test
    void emptyEvents() {
        assertTrue(new Solution().eventCounts(new String[]{}).isEmpty());
    }

    @Test
    void singleEvent() {
        Map<String, Integer> result = new Solution().eventCounts(new String[]{"DECLINED"});
        assertEquals(Set.of("DECLINED"), result.keySet());
        assertEquals(1, result.get("DECLINED"));
    }

    @Test
    void absentTypesMustNotAppear() {
        // Only LOGIN events — map must contain only "LOGIN", not TRANSFER/DECLINED/LOGOUT
        Map<String, Integer> result = new Solution().eventCounts(
                new String[]{"LOGIN", "LOGIN", "LOGIN"});
        assertEquals(Set.of("LOGIN"), result.keySet());
        assertEquals(3, result.get("LOGIN"));
    }

    @Test
    void orderMatters() {
        // The frequency map itself is order-independent for totals, but
        // this test verifies the algorithm processes every event in the stream
        // and does not skip any (e.g., off-by-one on loop bounds).
        // TRANSFER appears 3 times; any missed iteration would produce 2.
        Map<String, Integer> result = new Solution().eventCounts(
                new String[]{"TRANSFER", "LOGIN", "TRANSFER", "DECLINED", "TRANSFER"});
        assertEquals(3, result.get("TRANSFER"));
        assertEquals(1, result.get("LOGIN"));
        assertEquals(1, result.get("DECLINED"));
        assertFalse(result.containsKey("LOGOUT"), "LOGOUT was never seen — must not be in map");
    }

    @Test
    void allFourTypes() {
        Map<String, Integer> result = new Solution().eventCounts(
                new String[]{"LOGIN", "TRANSFER", "DECLINED", "LOGOUT"});
        assertEquals(Set.of("LOGIN", "TRANSFER", "DECLINED", "LOGOUT"), result.keySet());
        result.values().forEach(v -> assertEquals(1, v));
    }

    @Test
    void highRepetitionSingleType() {
        String[] events = new String[100];
        Arrays.fill(events, "TRANSFER");
        Map<String, Integer> result = new Solution().eventCounts(events);
        assertEquals(Set.of("TRANSFER"), result.keySet());
        assertEquals(100, result.get("TRANSFER"));
    }
}
